import Fixture from '../../data/fxitures/fixture';

const ResultsGridSummaryRow = (props : {team : string, summaryResults : Fixture[]}) => {

    const {team, summaryResults} = props;

    const totalGames = summaryResults.length;
    const totalWins = summaryResults.filter(result => result.result === "W").length;
    const totalDraws = summaryResults.filter(result => result.result === "D").length;
    const totalLosses = summaryResults.filter(result => result.result === "L").length;
    const totalGoals = summaryResults.filter(result => result.npScore).reduce((sum, currentValue) => sum + currentValue.npScore, 0);
    const totalGoalsAgainst = summaryResults.filter(result => result.oppScore).reduce((sum, currentValue) => sum + currentValue.oppScore, 0);
    const goalsDifference = totalGoals - totalGoalsAgainst;
    const totalPoints = summaryResults.filter(result => result.pts).reduce((sum, currentValue) => sum + currentValue.pts, 0);

    return (
        <tr>
            <td>{team}</td>
            <td>{totalGames}</td>
            <td>{totalWins}</td>
            <td>{totalDraws}</td>
            <td>{totalLosses}</td>
            <td>{totalGoals}</td>     
            <td>{totalGoalsAgainst}</td>       
            <td>{goalsDifference}</td>
            <td>{totalPoints}</td>
        </tr>          
    );

}
export default ResultsGridSummaryRow;
